```class Solution {
public:
    int minChanges(int n, int k) {
        int cnt = 0;
        while (n != k) {
            if (n < k) return -1;
            int x = n ^ k;
            cnt += __builtin_popcount(x);
            n ^= x;
        }
        return cnt;
    }
};
```
